sp_widget.client_script:
api.controller = function($scope, $location) {
    var c = this;

    // Track whether modal is open
    c.showAdvancedSearch = false;

    /* ==============================
       COLOR OPTIONS CONFIG
       ============================== */
    c.colorOptions = [{
            label: 'White',
            value: 'W',
            icon: 'white'
        },
        {
            label: 'Blue',
            value: 'U',
            icon: 'blue'
        },
        {
            label: 'Black',
            value: 'B',
            icon: 'black'
        },
        {
            label: 'Red',
            value: 'R',
            icon: 'red'
        },
        {
            label: 'Green',
            value: 'G',
            icon: 'green'
        },
        {
            label: 'Colorless',
            value: 'C',
            icon: 'colorless'
        }
    ];

    /* ==============================
       ADVANCED QUERY MODEL
       ============================== */
    c.advQuery = {
        name: '',
        type: '',
        rarity: '',
        colors: {} // dynamic checkbox map
    };

    /* ==============================
       NAVIGATION: Go to specific page
       ============================== */
    /* Description: Updates the URL with a new page parameter to trigger re-query
     * Parameters: [integer] - page: the page number to navigate to
     * Returns: None
     */
    c.goToPage = function(page) {
        if (!page || page < 1) return;

        // Copy current URL parameters
        var params = angular.copy($location.search());

        // Set new page
        params.p = page;

        // Update URL (Service Portal will re-run widget server)
        $location.search(params);
    };

    /* ==============================
       NEXT PAGE
       ============================== */
    /* Description: Navigates to the next page if available
     * Parameters: None
     * Returns: None
     */
    c.nextPage = function() {
        if ($scope.data.pagination && $scope.data.pagination.has_next) {
            c.goToPage($scope.data.pagination.page + 1);
        }
    };

    /* ==============================
       PREVIOUS PAGE
       ============================== */
    /* Description: Navigates to the previous page if available
     * Parameters: None
     * Returns: None
     */
    c.prevPage = function() {
        if ($scope.data.pagination && $scope.data.pagination.has_prev) {
            c.goToPage($scope.data.pagination.page - 1);
        }
    };

    /* ==============================
       FIRST PAGE
       ============================== */
    /* Description: Navigates to the first page
     * Parameters: None
     * Returns: None
     */
    c.firstPage = function() {
        c.goToPage(1);
    };

    /* ==============================
       LAST PAGE
       ============================== */
    /* Description: Navigates to the last page
     * Parameters: None
     * Returns: None
     */
    c.lastPage = function() {
        if ($scope.data.pagination) {
            c.goToPage($scope.data.pagination.total_pages);
        }
    };

    /* ==============================
       SEARCH FUNCTION
       ============================== */

    /* Description: Updates the URL with the search query and resets page to 1
     * Parameters: None
     * Returns: None
     */
    c.submitSearch = function() {
        var params = angular.copy($location.search());

        params.q = c.searchQuery; // set search query
        params.p = 1; // reset page to first

        $location.search(params); // triggers server reload with new query
    };

    /* ==============================
       DEBUG: Log current pagination
       ============================== */
    /* Description: Logs the current pagination object if debug is enabled
     * Parameters: None
     * Returns: None
     */
    c.debugPagination = function() {
        if ($scope.data.debug && $scope.data.pagination) {
            console.log('MTG Grid Pagination:', $scope.data.pagination);
        }
    };

    /* ==============================
       TOGGLE ADVANCED SEARCH
       ============================== */
    /* Description: Opens or closes the advanced search modal
     * Parameters: None
     * Returns: None
     */
    c.toggleAdvancedSearch = function() {
        c.showAdvancedSearch = !c.showAdvancedSearch;
        console.log(c.showAdvancedSearch);
    };

    /* ==============================
       SUBMIT ADVANCED SEARCH
       ============================== */
    /* Description: Applies advanced search selections to URL params and triggers server reload
     * Parameters: None
     * Returns: None
     */
    c.submitAdvancedSearch = function() {
        var params = angular.copy($location.search());

        let queryParts = [];

        if (c.advQuery.name) {
            queryParts.push('name:' + c.advQuery.name);
        }

        if (c.advQuery.type) {
            queryParts.push('type:' + c.advQuery.type);
        }

        if (c.advQuery.rarity) {
            queryParts.push('rarity:' + c.advQuery.rarity);
        }

        // COLORS (multi-select)
        let selectedColors = Object.keys(c.advQuery.colors)
            .filter(key => c.advQuery.colors[key]);

        if (selectedColors.length) {
            queryParts.push('color:' + selectedColors.join(','));
        }

        params.q = queryParts.join(';');
        params.p = 1;

        $location.search(params);
        c.showAdvancedSearch = false;
    };

    // Initial debug log
    c.debugPagination();
}

sp_widget.script:
(function() {

    /* ==============================
     * CONSTANTS
     * ============================== */
    const PARAMS = {
        DEBUG: 'db',
        DEBUG_METHODS: 'dbm'
    };

    /* ==============================
     * PARAM HELPERS
     * ============================== */
    function getStringParam(name, defaultValue) {
        var val = $sp.getParameter(name);
        return val ? val.toString() : defaultValue;
    }

    function getArrayParam(name) {
        var val = $sp.getParameter(name);
        if (!val) return [];
        return val.split(',').map(function(item) {
            return item.trim();
        }).filter(Boolean);
    }

    /* ==============================
     * USER CONTEXT
     * ============================== */
    const isLoggedIn = gs.getUserID() !== '';
    const isAdmin = gs.hasRole('admin');

    /* ==============================
     * DEBUG PARAMS
     * ============================== */
    const rawDebug = getStringParam(PARAMS.DEBUG, 'false');
    const rawDebugIgnoreMethods = getStringParam(PARAMS.DEBUG_METHODS, '');
    console.log(rawDebug + ' | ' + rawDebugIgnoreMethods);

    const debugEnabled = (
        (rawDebug === 'true' || rawDebug === '1') &&
        isLoggedIn &&
        isAdmin
    );

    const DebugIgnoreMethods = debugEnabled ? rawDebugIgnoreMethods : '';

    /* ==============================
     * SERVICES INIT
     * ============================== */
    const MTG_CONSTANTS = new x_759224_magic_c_0.mtg_constants(debugEnabled, DebugIgnoreMethods);
    //const MTG_UTILS = new x_759224_magic_c_0.magic_utils(debugEnabled, DebugIgnoreMethods);
    const PORTAL_UTILS = new x_759224_magic_c_0.mtg_portal_utils(debugEnabled, DebugIgnoreMethods, $sp, MTG_CONSTANTS);

    /* ==============================
     * CONFIG
     * ============================== */
    const CONFIG = {
        table: MTG_CONSTANTS.tables.CARDS,
        search_fields: ['name'],
        fields: ['name', 'short_description', 'sys_created_on'],
        order_by: 'name'
    };

    /* ==============================
     * EXECUTION
     * ============================== */
    let countRes = PORTAL_UTILS.getCount(CONFIG.table, CONFIG.search_fields);
    let queryRes = PORTAL_UTILS.queryTable(CONFIG);
    let paginationRes = PORTAL_UTILS.getPagination(countRes.record);

    /* ==============================
     * RESPONSE MAPPING
     * ============================== */
	data.records = queryRes.record || [];
    data.pagination = paginationRes.record || {};
    data.query = PORTAL_UTILS.query;
    data.debug = PORTAL_UTILS.debug;


    /* ==============================
     * OPTIONAL ERROR SURFACING
     * ============================== */
    data.errors = [];

    if (!countRes.success) data.errors.push(countRes.message);
    if (!queryRes.success) data.errors.push(queryRes.message);
    if (!paginationRes.success) data.errors.push(paginationRes.message);

})();
